class AVLNode:
    def __init__(self, val):
        self.val = val; self.left = self.right = None; self.height = 1

def height(n): return n.height if n else 0

def update_height(n):
    n.height = 1 + max(height(n.left), height(n.right))

def balance_factor(n): return height(n.left) - height(n.right)

def rotate_left(z):
    """Left rotation: z's right child (y) becomes the new root."""
    y       = z.right
    T2      = y.left          # T2 moves from y's left to z's right
    y.left  = z
    z.right = ___________     # attach T2
    update_height(___________) # update z first (it's now lower)
    update_height(y)           # then y
    return y                   # y is the new subtree root

