def rotate_right(y):
    x=y.left; T2=x.right; x.right=y; y.left=T2
    update_height(y); update_height(x); return x

def insert_avl(root, val):
    if not root: return AVLNode(val)
    if val < root.val: root.left = insert_avl(root.left, val)
    else: root.right = insert_avl(root.right, val)
    update_height(root)
    bf = balance_factor(root)
    if bf > 1 and val < root.left.val:   return rotate_right(root)
    if bf < -1 and val > root.right.val: return rotate_left(root)
    if bf > 1 and val > root.left.val:   root.left=rotate_left(root.left); return rotate_right(root)
    if bf < -1 and val < root.right.val: root.right=rotate_right(root.right); return rotate_left(root)
    return root

def inorder(r):
    if not r: return []
    return inorder(r.left)+[r.val]+inorder(r.right)

root=None
for v in [30,20,10,25,40,50]: root=insert_avl(root,v)
assert inorder(root)==[10,20,25,30,40,50],'In-order sorted'
assert abs(balance_factor(root))<=1,'Root balanced'
